mapper.select:
SELECT * FROM chat_session
WHERE user_id = #{userId} OR target_id = #{userId}
ORDER BY update_time DESC

mapper.update:
UPDATE chat_session
SET last_message = #{lastMessage}, last_message_time = NOW(), update_time = NOW()
WHERE session_id = #{sessionId}

UPDATE chat_session
SET unread_count = unread_count + 1, update_time = NOW()
WHERE session_id = #{sessionId}

UPDATE chat_session
SET unread_count = 0, update_time = NOW()
WHERE session_id = #{sessionId}
